# Example: a minimal Praefect-style routing decision (pseudocode)

# repo_map is stored in Postgres: repo -> [primary, replica1, replica2]
func routeRequest(repo, preferReplica=false) -> target {
  locations = repo_map.lookup(repo)
  if preferReplica {
    // pick one replica with least lag
    return pickLeastLaggingReplica(locations.replicas)
  }
  return locations.primary
}

